    const ans: number[] = [];
    for (const [li, ri, threshold] of queries) {
        const sub = nums.slice(li, ri + 1);
        const freq = new Map<number, number>();
        for (const num of sub) {
            freq.set(num, (freq.get(num) || 0) + 1);
        }
        let maxFreq = -1;
        let bestNum = -1;
        for (const [num, count] of freq.entries()) {
            if (count >= threshold) {
                if (count > maxFreq || (count === maxFreq && num < bestNum)) {
                    maxFreq = count;
                    bestNum = num;
                }
            }
        }
        ans.push(bestNum === -1 ? -1 : bestNum);
    }
    return ans;
}

